  //---------------------------------------------------------------------
  //---------------------------------------------------------------------
  ::grpc::Status NiRFmxBluetoothGenService::ReadWaveformFromFile(::grpc::ServerContext* context, const ReadWaveformFromFileRequest* request, ReadWaveformFromFileResponse* response)
  {
    if (context->IsCancelled()) {
      return ::grpc::Status::CANCELLED;
    }
    try {
      auto file_path_mbcs = convert_from_grpc<std::string>(request->file_path());
      char* file_path = (char*)file_path_mbcs.c_str();
      auto waveform_name_mbcs = convert_from_grpc<std::string>(request->waveform_name());
      char* waveform_name = (char*)waveform_name_mbcs.c_str();
      int64 offset = request->offset();
      int64 count = request->count();
      float64 t0 {};
      float64 dt {};
      NIComplexNumber_struct waveform {};
      int32 actual_num_waveform_samples {};
      float64 iq_rate {};
      float64 headroom {};
      int32 eof {};
      while (true) {
        auto status = library_->ReadWaveformFromFile(file_path, waveform_name, offset, count, &t0, &dt, nullptr, 0, &actual_num_waveform_samples, &iq_rate, &headroom, &eof);
        if (!status_ok(status)) {
          return ConvertApiErrorStatusForNiBTSGSession(context, status, 0);
        }
        auto waveform_size = actual_num_waveform_samples;
        status = library_->ReadWaveformFromFile(file_path, waveform_name, offset, count, &t0, &dt, &waveform, waveform_size, &actual_num_waveform_samples, &iq_rate, &headroom, &eof);
        if (status == kErrorReadBufferTooSmall || status == kWarningCAPIStringTruncatedToFitBuffer) {
          // buffer is now too small, try again
          continue;
        }
        if (!status_ok(status)) {
          return ConvertApiErrorStatusForNiBTSGSession(context, status, 0);
        }
        response->set_status(status);
        response->set_t0(t0);
        response->set_dt(dt);
        convert_to_grpc(waveform, response->mutable_waveform());
        {
          auto shrunk_size = actual_num_waveform_samples;
          auto current_size = response->mutable_waveform()->size();
          if (shrunk_size != current_size) {
            response->mutable_waveform()->DeleteSubrange(shrunk_size, current_size - shrunk_size);
          }
        }
        response->set_actual_num_waveform_samples(actual_num_waveform_samples);
        response->set_iq_rate(iq_rate);
        response->set_headroom(headroom);
        response->set_eof(eof);
        return ::grpc::Status::OK;
      }
    }
    catch (nidevice_grpc::NonDriverException& ex) {
      return ex.GetStatus();
    }
  }

