  //---------------------------------------------------------------------
  //---------------------------------------------------------------------
  ::grpc::Status NiRFmxBluetoothGenService::SetAntennaRelativePhaseAndAmplitude(::grpc::ServerContext* context, const SetAntennaRelativePhaseAndAmplitudeRequest* request, SetAntennaRelativePhaseAndAmplitudeResponse* response)
  {
    if (context->IsCancelled()) {
      return ::grpc::Status::CANCELLED;
    }
    try {
      auto session_grpc_session = request->session();
      niBTSGSession session = session_repository_->access_session(session_grpc_session.name());
      auto channel_string_mbcs = convert_from_grpc<std::string>(request->channel_string());
      char* channel_string = (char*)channel_string_mbcs.c_str();
      auto relative_amplitude_db = const_cast<float64*>(request->relative_amplitude_db().data());
      auto relative_phase_deg = const_cast<float64*>(request->relative_phase_deg().data());
      auto array_size_determine_from_sizes = std::array<int, 2>
      {
        request->relative_amplitude_db_size(),
        request->relative_phase_deg_size()
      };
      const auto array_size_size_calculation = calculate_linked_array_size(array_size_determine_from_sizes, true);

      if (array_size_size_calculation.match_state == MatchState::MISMATCH) {
        return ::grpc::Status(::grpc::INVALID_ARGUMENT, "The sizes of linked repeated fields [relative_amplitude_db, relative_phase_deg] do not match");
      }
      // NULL out optional params with zero sizes.
      if (array_size_size_calculation.match_state == MatchState::MATCH_OR_ZERO) {
        relative_amplitude_db = request->relative_amplitude_db_size() ? std::move(relative_amplitude_db) : nullptr;
        relative_phase_deg = request->relative_phase_deg_size() ? std::move(relative_phase_deg) : nullptr;
      }
      auto array_size = array_size_size_calculation.size;

      auto status = library_->SetAntennaRelativePhaseAndAmplitude(session, channel_string, relative_amplitude_db, relative_phase_deg, array_size);
      if (!status_ok(status)) {
        return ConvertApiErrorStatusForNiBTSGSession(context, status, session);
      }
      response->set_status(status);
      return ::grpc::Status::OK;
    }
    catch (nidevice_grpc::NonDriverException& ex) {
      return ex.GetStatus();
    }
  }

